import { getVal } from '../../../utils/zcutils';
import { effects, getPatternProp } from '../../../effects/zceffects';
import { getSVGImage } from '../../../effects/dataImage';

function getPattern(_, applied) {
    let { context, defsPath = '', rendererMode = 'svg' } = _,
        { color, pattern, opacity, size, staticColor } = applied,
        _rendererMode = rendererMode === 'base64' ? 'svg' : rendererMode;

    return (d, i) => {
        let _pattern = getVal(pattern, [d, i]),
            _color = getVal(color, [d, i]),
            _opacity = getVal(opacity, [d, i]),
            //
            prop = getPatternProp(_pattern, _color, _opacity, size, staticColor), // TODO: size
            args = { renderTo: context, returnSVGimage: rendererMode === 'base64' },
            patternEle = effects.get(effects[`${_rendererMode}_patterns`], `${_rendererMode}PatternFill`, prop, args);

        return rendererMode === 'base64'
            ? `url(${getSVGImage(patternEle, true).url})`
            : rendererMode === 'svg'
            ? `url(${defsPath}#${patternEle})`
            : patternEle;
    };
}

export { getPattern };
